import { useState, useEffect, useCallback } from 'react';

// Custom event name to synchronize state across different components
const WISHLIST_UPDATE_EVENT = 'wishlist_updated';

export const useWishlist = () => {
    const [items, setItems] = useState([]);

    // 🚀 Initialize and listen for changes
    useEffect(() => {
        // 1. Load initial data from localStorage
        const loadWishlist = () => {
            try {
                const saved = localStorage.getItem('wishlist');
                if (saved) {
                    setItems(JSON.parse(saved));
                }
            } catch (error) {
                console.error("Failed to parse wishlist from local storage", error);
            }
        };

        loadWishlist();

        // 2. Listen for our custom event (Dispatched when adding/removing)
        const handleUpdate = () => {
            loadWishlist();
        };

        // 3. Listen for changes in other tabs
        const handleStorage = (e) => {
            if (e.key === 'wishlist') {
                loadWishlist();
            }
        };

        window.addEventListener(WISHLIST_UPDATE_EVENT, handleUpdate);
        window.addEventListener('storage', handleStorage);

        return () => {
            window.removeEventListener(WISHLIST_UPDATE_EVENT, handleUpdate);
            window.removeEventListener('storage', handleStorage);
        };
    }, []);

    // 🚀 Helper to broadcast changes to the Navbar
    const broadcastUpdate = (newItems) => {
        localStorage.setItem('wishlist', JSON.stringify(newItems));
        setItems(newItems);
        // Fire the custom event so the Navbar knows to re-render!
        window.dispatchEvent(new Event(WISHLIST_UPDATE_EVENT));
    };

    const addItem = useCallback((productId, variantId, name, price, image) => {
        const currentItems = JSON.parse(localStorage.getItem('wishlist') || '[]');

        // Don't add duplicates
        const exists = currentItems.some(
            (item) => item.productId === productId && item.variantId === variantId
        );

        if (!exists) {
            const newItems = [...currentItems, { productId, variantId, name, price, image }];
            broadcastUpdate(newItems);
        }
    }, []);

    const removeItem = useCallback((productId, variantId) => {
        const currentItems = JSON.parse(localStorage.getItem('wishlist') || '[]');
        const newItems = currentItems.filter(
            (item) => !(item.productId === productId && item.variantId === variantId)
        );
        broadcastUpdate(newItems);
    }, []);

    const toggleItem = useCallback((productData) => {
        const { productId, variantId, name, price, image } = productData;
        const currentItems = JSON.parse(localStorage.getItem('wishlist') || '[]');

        const exists = currentItems.some(
            (item) => item.productId === productId && item.variantId === variantId
        );

        if (exists) {
            const newItems = currentItems.filter(
                (item) => !(item.productId === productId && item.variantId === variantId)
            );
            broadcastUpdate(newItems);
        } else {
            const newItems = [...currentItems, { productId, variantId, name, price, image }];
            broadcastUpdate(newItems);
        }
    }, []);

    const clearWishlist = useCallback(() => {
        broadcastUpdate([]);
    }, []);

    const isInWishlist = useCallback((productId, variantId) => {
        return items.some(
            (item) => item.productId === productId && item.variantId === variantId
        );
    }, [items]);

    return {
        items,
        addItem,
        removeItem,
        toggleItem,
        clearWishlist,
        isInWishlist,
    };
};
